// ============================================================================
// uncertainty_check — Heuristic Review Tool (Review Agent role, deterministic)
//
// BONUS TOOL per take-home spec. Implements the second-opinion reviewer
// guardrail against the extraction agent's optimism bias.
//
// ARCHITECTURE NOTE (writeup material):
// Iteration 1 used a Haiku-based Review Agent. Production testing on a 50K
// ITPM limit showed that a second LLM call in the critical path doubled token
// usage per opportunity, causing rate-limit collapse. Iteration 2 (this
// implementation) encodes the same failure modes the LLM-based reviewer was
// catching as explicit deterministic rules: same role, same input/output
// contract, same veto rule — at zero token cost, sub-100ms latency, 100%
// auditable.
//
// Deterministic-first principle taken to its logical conclusion: subjective
// review is not necessarily an LLM job. When failure modes are
// characterizable, deterministic checks are cheaper, faster, more auditable,
// and they free the ITPM budget for the primary extraction call where the
// LLM is genuinely needed.
//
// INPUT  : { utterances[], draft_payload, sonnet_decision: { abstain, confidence } }
// OUTPUT : { should_abstain, signal_strength, reason, overrides_sonnet,
//            flags[], features{}, method, reviewer_model } — same contract
// ============================================================================

const input = $input.first().json;

const utterances = Array.isArray(input.utterances) ? input.utterances : [];
const draftPayload = input.draft_payload || {};
const sonnetDecision = input.sonnet_decision || {};
const sonnetAbstain = sonnetDecision.abstain === true;
const sonnetConfidence = typeof sonnetDecision.confidence === 'number' ? sonnetDecision.confidence : 0;

function truncate(s, max) { if (typeof s !== 'string') return ''; return s.length > max ? s.substring(0, max) : s; }

function stashDebug(debug) {
  try {
    if ($execution && typeof $execution.customData?.set === 'function') {
      $execution.customData.set('uncertainty_check_debug', JSON.stringify(debug).slice(0, 8000));
    }
  } catch (e) { /* customData unavailable in test mode -- silent */ }
}

function countFilledFields(payload) {
  if (!payload || typeof payload !== 'object') return 0;
  let count = 0;
  if (payload.stage) count++;
  if (payload.amount_usd != null) count++;
  if (payload.close_date) count++;
  if (payload.next_step && payload.next_step.description) count++;
  if (payload.meddpicc && typeof payload.meddpicc === 'object') {
    const keys = Object.keys(payload.meddpicc);
    for (let i = 0; i < keys.length; i++) {
      const v = payload.meddpicc[keys[i]];
      if (typeof v === 'string' && v.length > 0) count++;
    }
  }
  if (Array.isArray(payload.risks)) count += payload.risks.length;
  return count;
}

function joinUtterances(utts) {
  const parts = [];
  for (let i = 0; i < utts.length; i++) {
    const u = utts[i];
    if (u && typeof u.text === 'string') parts.push(u.text.toLowerCase());
  }
  return parts.join(' | ');
}

function countMatches(text, patterns) {
  let n = 0;
  for (let i = 0; i < patterns.length; i++) { if (patterns[i].test(text)) n++; }
  return n;
}

const NEUTRAL_PATTERNS = [
  /\bnothing new\b/, /\bdo(?:n['’]?t| not) have much new\b/,
  /\bmaybe.{0,20}weeks?\b/, /\bmaybe.{0,20}days?\b/,
  /\bi(?:['’]?ll| will) ping you\b/, /\bstill waiting\b/,
  /\bkeep me posted\b/, /\bsounds good\b/, /\bping you\b/
];
const SMALLTALK_PATTERNS = [
  /\btrip\b/, /\bvacation\b/, /\bweekend\b/, /\bhow.{0,8}you\b/,
  /\blisbon\b/, /\bparis\b/, /\benjoy\b/, /\bamazing\b/, /\brecommend\b/
];
const STRONG_SIGNAL_PATTERNS = [
  /\$[\d,]+/, /\b\d+\s*k\b/i,
  /\b(cmo|ceo|cfo|coo|cto|vp)\b/i,
  /\b(annual|quarterly|monthly)\b/i,
  /\b(closed[ -]won|closed[ -]lost)\b/i,
  /\bsigner\b/i, /\bcontract\b/i
];

const utteranceCount = utterances.length;
const filledFields = countFilledFields(draftPayload);
const text = joinUtterances(utterances);

const neutralHits = countMatches(text, NEUTRAL_PATTERNS);
const smalltalkHits = countMatches(text, SMALLTALK_PATTERNS);
const strongHits = countMatches(text, STRONG_SIGNAL_PATTERNS);

let signal_strength;
if (strongHits >= 2 && filledFields >= 3) {
  signal_strength = 'strong';
} else if (strongHits >= 1 && filledFields >= 2) {
  signal_strength = 'moderate';
} else if (neutralHits >= 1 && strongHits === 0) {
  signal_strength = 'weak';
} else if (smalltalkHits >= 2 && strongHits === 0 && filledFields === 0) {
  signal_strength = 'none';
} else if (filledFields === 0 && strongHits === 0) {
  signal_strength = 'weak';
} else {
  signal_strength = 'moderate';
}

let should_abstain = (signal_strength === 'none' || signal_strength === 'weak');

const flags = [];
const reasons = [];

if (smalltalkHits >= 1) { flags.push('smalltalk_detected'); reasons.push('smalltalk patterns (' + smalltalkHits + ')'); }
if (neutralHits >= 1) { flags.push('vague_commitment'); reasons.push('vague-commitment patterns (' + neutralHits + ')'); }
if (strongHits >= 1) { flags.push('strong_signal_pattern'); reasons.push('strong-signal patterns (' + strongHits + ')'); }
if (sonnetAbstain === false && filledFields < 2) { flags.push('rich_decision_with_few_fields'); reasons.push('extraction marked rich but only ' + filledFields + ' field(s) populated'); }
if (sonnetAbstain === true && filledFields >= 3) { flags.push('abstain_with_rich_payload'); reasons.push('abstain decision contradicts ' + filledFields + ' populated fields'); }
if (utteranceCount < 6 && sonnetAbstain === false && sonnetConfidence > 0.7) { flags.push('overconfident_thin_transcript'); reasons.push('high confidence (' + sonnetConfidence + ') on short transcript (' + utteranceCount + ' utterances)'); }
if (draftPayload && draftPayload.type === 'object' && draftPayload.properties) { flags.push('schema_echo_detected'); reasons.push('payload looks like schema definition rather than values'); should_abstain = true; signal_strength = 'unknown'; }
const LATE_STAGES = ['negotiation', 'proposal', 'closed_won'];
if (LATE_STAGES.indexOf(draftPayload.stage) !== -1 && !draftPayload.amount_usd) { flags.push('late_stage_no_amount'); reasons.push('stage ' + draftPayload.stage + ' but no amount_usd'); }
if (draftPayload.next_step && (!draftPayload.next_step.owner || !draftPayload.next_step.due_date)) { flags.push('incomplete_next_step'); reasons.push('next_step missing owner or due_date'); }

const reason = truncate(
  flags.length > 0
    ? 'heuristic_review: ' + flags.join(', ') + ' | ' + reasons.join('; ')
    : 'heuristic_review: signal_' + signal_strength + ', ' + filledFields + ' filled fields',
  500
);

const overrides_sonnet = (sonnetAbstain === false) && (should_abstain === true);

stashDebug({
  should_abstain, signal_strength, reason, overrides_sonnet, flags,
  features: { utterance_count: utteranceCount, filled_fields: filledFields, neutral_hits: neutralHits, smalltalk_hits: smalltalkHits, strong_hits: strongHits },
  method: 'deterministic_heuristics_v1', reviewer_model: null
});

return [{ json: {
  should_abstain: should_abstain,
  signal_strength: signal_strength,
  reason: reason,
  overrides_sonnet: overrides_sonnet,
  flags: flags
}}];
